import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useAuth } from '../../context/AuthContext';
import PaymentModal from '../../components/student/PaymentModal';

const Icons = {
  Bus: () => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
      <path d="M19 17h2a2 2 0 0 0 2-2V7a2 2 0 0 0-2-2H3a2 2 0 0 0-2 2v8a2 2 0 0 0 2 2h2"/>
      <circle cx="7" cy="17" r="2"/><circle cx="17" cy="17" r="2"/><path d="M5 17h10M13 5v8M1 9h22M5 5v4"/>
    </svg>
  ),
  Wallet: () => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M20 12V8H6a2 2 0 0 1-2-2c0-1.1.9-2 2-2h12v4"/>
      <path d="M4 6v12c0 1.1.9 2 2 2h14v-4"/>
      <path d="M18 12a2 2 0 0 0-2 2c0 1.1.9 2 2 2h4v-4h-4z"/>
    </svg>
  ),
  Receipt: () => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M4 2v20l2-1 2 1 2-1 2 1 2-1 2 1 2-1 2 1V2l-2 1-2-1-2 1-2-1-2 1-2-1-2 1-2-1z"/>
      <path d="M16 8h-6a2 2 0 1 0 0 4h4a2 2 0 1 1 0 4H8"/><line x1="12" y1="6" x2="12" y2="18"/>
    </svg>
  ),
  MapPin: () => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx="12" cy="10" r="3"/>
    </svg>
  )
};

export default function StudentDashboard() {
  const { user } = useAuth();
  const [profile, setProfile] = useState(null);
  const [fees, setFees] = useState([]);
  const [loading, setLoading] = useState(true);
  const [payFee, setPayFee] = useState(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [profRes, feesRes] = await Promise.all([
          axios.get('/students/profile'),
          axios.get('/fees/my')
        ]);
        setProfile(profRes.data);
        setFees(feesRes.data);
      } catch (e) {
        console.error(e);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  const fmt = (n) => `₹${Number(n || 0).toLocaleString('en-IN')}`;

  const pending = fees.filter(f => f.status === 'pending' || f.status === 'overdue');
  const paid = fees.filter(f => f.status === 'paid');
  const totalPending = pending.reduce((s, f) => s + parseFloat(f.totalAmount), 0);
  const nextDue = pending.sort((a,b) => new Date(a.dueDate) - new Date(b.dueDate))[0];

  if (loading) return <div className="loading-screen" style={{ height: 300 }}><div className="spinner" /></div>;

  return (
    <div>
      {/* Welcome Hero */}
      <div style={{
        background: 'linear-gradient(135deg, #0f172a 0%, #1e1b4b 60%, #0f3d8c 100%)',
        borderRadius: '24px', padding: '40px', marginBottom: 32, color: 'white',
        position: 'relative', overflow: 'hidden', boxShadow: 'var(--shadow-xl)'
      }}>
        <div style={{ position: 'relative', zIndex: 1 }}>
          <div style={{ fontSize: 13, fontWeight: 700, opacity: 0.7, textTransform: 'uppercase', letterSpacing: 2, marginBottom: 12 }}>Student Dashboard</div>
          <h2 style={{ fontSize: 32, fontWeight: 800, color: 'white', marginBottom: 8 }}>Hello, {user?.name?.split(' ')[0]} 👋</h2>
          <p style={{ fontSize: 16, opacity: 0.8, maxWidth: 600 }}>
            {profile?.studentId} · {profile?.department} · Year {profile?.year}
            {profile?.section && ` · Sec ${profile.section}`}
          </p>

          <div style={{ display: 'flex', gap: 16, marginTop: 32 }}>
            <div style={{ background: 'rgba(255,255,255,0.1)', padding: '12px 20px', borderRadius: 16, backdropFilter: 'blur(10px)' }}>
              <div style={{ fontSize: 11, opacity: 0.6, textTransform: 'uppercase', fontWeight: 800 }}>Assigned Route</div>
              <div style={{ fontWeight: 700, fontSize: 18 }}>{profile?.route ? `🚌 Route ${profile.route.routeNumber}` : 'Not Assigned'}</div>
            </div>
            <div style={{ background: 'rgba(255,255,255,0.1)', padding: '12px 20px', borderRadius: 16, backdropFilter: 'blur(10px)' }}>
              <div style={{ fontSize: 11, opacity: 0.6, textTransform: 'uppercase', fontWeight: 800 }}>Enrollment Status</div>
              <div style={{ fontWeight: 700, fontSize: 18, color: '#4ade80' }}>Active</div>
            </div>
          </div>
        </div>
        {/* Decorative elements */}
        <div style={{ 
          position: 'absolute', right: -40, top: -40, width: 240, height: 240, 
          background: 'var(--primary)', filter: 'blur(80px)', opacity: 0.3, borderRadius: '50%' 
        }} />
      </div>

      {/* Stats Cards */}
      <div className="stats-grid">
        <div className="stat-card blue">
          <div className="stat-icon"><Icons.Bus /></div>
          <div className="stat-label">Bus Route</div>
          <div className="stat-value" style={{ fontSize: 20 }}>{profile?.route?.routeName || '—'}</div>
          <div className="stat-sub">{profile?.boardingPoint || 'Select boarding point in profile'}</div>
        </div>

        <div className="stat-card red">
          <div className="stat-icon"><Icons.Wallet /></div>
          <div className="stat-label">Instant Due</div>
          <div className="stat-value" style={{ color: totalPending > 0 ? 'var(--danger)' : 'var(--text)' }}>
            {fmt(totalPending)}
          </div>
          <div className="stat-sub">{pending.length} pending payments</div>
        </div>

        <div className="stat-card green">
          <div className="stat-icon"><Icons.Receipt /></div>
          <div className="stat-label">Total Paid</div>
          <div className="stat-value">{fmt(paid.reduce((s, f) => s + parseFloat(f.totalAmount), 0))}</div>
          <div className="stat-sub">Across {paid.length} successful transactions</div>
        </div>
      </div>

      {/* Pay Banner for dues */}
      {nextDue && (
        <div style={{
          background: 'linear-gradient(90deg, #fef2f2 0%, #fff 100%)',
          border: '1.5px solid #fee2e2', borderRadius: '20px', padding: '24px 32px',
          display: 'flex', alignItems: 'center', justifyContent: 'space-between',
          marginBottom: 32, boxShadow: 'var(--shadow-sm)'
        }}>
          <div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 4 }}>
              <span style={{ fontSize: 20 }}>🚨</span>
              <h3 style={{ fontSize: 18, fontWeight: 800 }}>Next Payment Due</h3>
            </div>
            <p style={{ color: 'var(--text-muted)', fontSize: 14 }}>
              Fee for <strong>{nextDue.feePeriod || nextDue.feeMonth}</strong> is due by <strong>{nextDue.dueDate}</strong>. 
              Avoid late charges by paying early.
            </p>
          </div>
          <button className="btn btn-primary btn-lg" onClick={() => setPayFee(nextDue)}>
            Pay {fmt(nextDue.totalAmount)} →
          </button>
        </div>
      )}

      <div className="charts-grid" style={{ gridTemplateColumns: '1fr' }}>
        <div className="card">
          <div className="card-header">
            <h3 className="card-title"><span>📅</span> Recent Fee History</h3>
            <button className="btn btn-outline btn-sm" onClick={() => navigate('/student/fees')}>View All Records</button>
          </div>
          <div className="table-wrap">
            <table>
              <thead>
                <tr>
                  <th>Fee Period</th>
                  <th>Type</th>
                  <th>Amount</th>
                  <th>Paid On</th>
                  <th>Status</th>
                  <th>Action</th>
                </tr>
              </thead>
              <tbody>
                {fees.length === 0 ? (
                  <tr><td colSpan={6} style={{ textAlign: 'center', padding: 40, color: 'var(--text-muted)' }}>No fee records found.</td></tr>
                ) : fees.slice(0, 5).map(f => (
                  <tr key={f.id}>
                    <td><strong>{f.feePeriod || f.feeMonth}</strong></td>
                    <td style={{ textTransform: 'capitalize' }}>{f.feeType}</td>
                    <td><strong>{fmt(f.totalAmount)}</strong></td>
                    <td className="text-muted">{f.paidDate || '—'}</td>
                    <td><span className={`badge badge-${f.status}`}>{f.status}</span></td>
                    <td>
                      {f.status === 'paid' ? (
                        <span style={{ color: 'var(--success)', fontWeight: 700, fontSize: 12 }}>✓ Completed</span>
                      ) : (
                        <button className="btn btn-primary btn-sm" onClick={() => setPayFee(f)}>Pay Now</button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {payFee && (
        <PaymentModal
          fee={payFee}
          onClose={() => setPayFee(null)}
          onSuccess={() => {
            setPayFee(null);
            // Refresh counts
            axios.get('/fees/my').then(r => setFees(r.data));
          }}
        />
      )}
    </div>
  );
}
